@SuppressWarnings("rawtypes")
	private static void initInternal(File configFile, String outputPath, boolean stdOut) throws IOException
	{
		List<Appender> appenders = new ArrayList<Appender>();

		// Retrieve all existing appenders
		Enumeration apps = LogManager.getRootLogger().getAllAppenders();
		while(apps.hasMoreElements()) {
			Appender appender = (Appender)apps.nextElement();
			if (!(appender instanceof ConsoleAppender || appender instanceof FileAppender)) 
				appenders.add( appender );
		}

		Properties lprops = new Properties();
		FileInputStream in = new FileInputStream(configFile);
		lprops.load(in);
		in.close();
		LogManager.resetConfiguration();

		if (lprops.getProperty("log4j.appender.orslogfile.File") == null)
			lprops.put("log4j.appender.orslogfile.File", outputPath);

		PropertyConfigurator.configure(lprops);

		if (!stdOut) {
            apps = org.apache.log4j.Logger.getRootLogger().getAllAppenders();
            while (apps.hasMoreElements()) {
            	Appender appender = (Appender)apps.nextElement();
                if (appender instanceof org.apache.log4j.ConsoleAppender) {
                    org.apache.log4j.Logger.getRootLogger().removeAppender(appender);
                }
            }
		} 

		for (Appender appender : appenders ) 
			LogManager.getRootLogger().addAppender( appender );
	}

@Override
  public IMethod getCalleeTarget(CGNode caller, CallSiteReference site, IClass receiver) {
    IMethod target = base.getCalleeTarget(caller, site, receiver);
    if (target != null && target.getReference().equals(loadFileFunRef)) {

      Set<String> names = new HashSet<String>();
      SSAInstruction call = caller.getIR().getInstructions()[caller.getIR().getCallInstructionIndices(site).intIterator().next()];
      if (call.getNumberOfUses() > 1) {
        LocalPointerKey fileNameV = new LocalPointerKey(caller, call.getUse(1));
        OrdinalSet<InstanceKey> ptrs = builder.getPointerAnalysis().getPointsToSet(fileNameV);
        for(InstanceKey k : ptrs) {
          if (k instanceof ConstantKey) {
            Object v = ((ConstantKey)k).getValue();
            if (v instanceof String) {
              names.add((String)v);
            }
          }
        }

        if (names.size() == 1) {
          String str = names.iterator().next();
          try {
            JavaScriptLoader cl = (JavaScriptLoader) builder.getClassHierarchy().getLoader(JavaScriptTypes.jsLoader);
            URL url = new URL(builder.getBaseURL(), str);
            if(!loadedFiles.contains(url)) {
              // try to open the input stream for the URL.  if it fails, we'll get an IOException and fall through to default case
              InputStream inputStream = url.openConnection().getInputStream();
              inputStream.close();
              JSCallGraphUtil.loadAdditionalFile(builder.getClassHierarchy() , cl, url);
              loadedFiles.add(url);
              IClass script = builder.getClassHierarchy().lookupClass(TypeReference.findOrCreate(cl.getReference(), "L" + url.getFile()));
              return script.getMethod(JavaScriptMethods.fnSelector);
            }
          } catch (MalformedURLException e1) {
            // do nothing, fall through and return 'target'
          } catch (IOException e) {
            // do nothing, fall through and return 'target'
          } catch (RuntimeException e) {
            // do nothing, fall through and return 'target'
          }
        }
      }
    }

    return target;
  }

@SuppressWarnings("ThrowableResultOfMethodCallIgnored")
  @Override
  public void render(Context ctx, HealthCheckResults healthCheckResults) throws Exception {
    ByteBuf buffer = byteBufAllocator.buffer();
    boolean first = true;
    boolean unhealthy = false;

    try {
      Writer writer = new OutputStreamWriter(new BufferedOutputStream(new ByteBufOutputStream(buffer)));
      for (Map.Entry<String, HealthCheck.Result> entry : healthCheckResults.getResults().entrySet()) {
        if (first) {
          first = false;
        } else {
          writer.write("\n");
        }
        String name = entry.getKey();
        HealthCheck.Result result = entry.getValue();
        writer.append(name).append(" : ").append(result.isHealthy() ? "HEALTHY" : "UNHEALTHY");
        if (!result.isHealthy()) {
          unhealthy = true;
          writer.append(" [").append(result.getMessage()).append("]");
          if (result.getError() != null) {
            writer.append(" [").append(result.getError().toString()).append("]");
          }
        }
      }
      writer.close();
    } catch (Exception e) {
      buffer.release();
      throw e;
    }

    ctx.getResponse()
      .contentTypeIfNotSet(HttpHeaderConstants.PLAIN_TEXT_UTF8)
      .status(unhealthy ? 503 : 200)
      .send(buffer);
  }

public void write(Migration migration, File file) {

    try {

      FileWriter writer = new FileWriter(file);
      writer.write("<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n");
      writer.write("<!DOCTYPE xml>\n");
      if (comment != null) {
        writer.write("<!-- ");
        writer.write(comment);
        writer.write(" -->\n");
      }

      JAXBContext jaxbContext = JAXBContext.newInstance(Migration.class);
      Marshaller marshaller = jaxbContext.createMarshaller();
      marshaller.setProperty(Marshaller.JAXB_FORMATTED_OUTPUT, Boolean.TRUE);
      marshaller.setProperty(Marshaller.JAXB_FRAGMENT, Boolean.TRUE);

      marshaller.marshal(migration, writer);

      writer.close();

    } catch (IOException | JAXBException e) {
      throw new RuntimeException(e);
    }
  }

@Override
    public PrivateKey parseValue(String value) throws GuacamoleServerException {

        if (value == null || value.isEmpty())
            return null;

        try {

            // Open and read the file specified in the configuration.
            File keyFile = new File(value);
            FileInputStream keyStreamIn = new FileInputStream(keyFile);
            ByteArrayOutputStream keyStreamOut = new ByteArrayOutputStream();
            byte[] keyBuffer = new byte[1024];

            for (int readBytes; (readBytes = keyStreamIn.read(keyBuffer)) != -1;)
                keyStreamOut.write(keyBuffer, 0, readBytes);

            keyStreamIn.close();
            final byte[] keyBytes = keyStreamOut.toByteArray();

            // Set up decryption infrastructure
            KeyFactory keyFactory = KeyFactory.getInstance("RSA");
            KeySpec keySpec = new PKCS8EncodedKeySpec(keyBytes);
            return keyFactory.generatePrivate(keySpec);

        }
        catch (FileNotFoundException e) {
            throw new GuacamoleServerException("Could not find the specified key file.", e);
        }
        catch (IOException e) {
            throw new GuacamoleServerException("Could not read in the specified key file.", e);
        }
        catch (NoSuchAlgorithmException e) {
            throw new GuacamoleServerException("RSA algorithm is not available.", e);
        }
        catch (InvalidKeySpecException e) {
            throw new GuacamoleServerException("Key is not in expected PKCS8 encoding.", e);
        }

    }

