public  String request(String method, String url, String req,
			int userTimeout) throws Exception {
		String result = "";
		BufferedReader in = null;
		try{
            if (this.url != url)
                this.newHttpConnection(url);

            this.connection.setConnectTimeout(timeout+userTimeout);
            this.connection.setReadTimeout(timeout+userTimeout);

			if (method.equals("POST")) {
				((HttpURLConnection)this.connection).setRequestMethod("POST");

				this.connection.setDoOutput(true);
				this.connection.setDoInput(true);
				DataOutputStream out = new DataOutputStream(this.connection.getOutputStream());
				out.writeBytes(req);
				out.flush();
				out.close();
			}

			this.connection.connect();
			int status = ((HttpURLConnection)this.connection).getResponseCode();
			if(status != 200)
				throw new CMQServerException(status);

			in = new BufferedReader(new InputStreamReader(connection.getInputStream(),"utf-8"));

			String line;
			while ((line = in.readLine()) != null) {
				result += line;
			}
		}catch(Exception e){
			throw e;
		}finally{
			try {
				if (in != null) 
					in.close();
			} catch (Exception e2) {
				throw e2;
			}
		}

		return result;
	}

private void testEmail() {
    final ProgressWindow progressWindow = GameRunner.newProgressWindow("Sending test email...");
    progressWindow.setVisible(true);
    final Runnable runnable = () -> {
      // initialize variables to error state, override if successful
      String message = "An unknown occurred, report this as a bug on the TripleA dev forum";
      int messageType = JOptionPane.ERROR_MESSAGE;
      try {
        final String html = "<html><body><h1>Success</h1><p>This was a test email sent by TripleA<p></body></html>";
        final File dummy = new File(ClientFileSystemHelper.getUserRootFolder(), "dummySave.txt");
        dummy.deleteOnExit();
        final FileOutputStream fout = new FileOutputStream(dummy);
        fout.write("This file would normally be a save game".getBytes());
        fout.close();
        ((IEmailSender) getBean()).sendEmail("TripleA Test", html, dummy, "dummy.txt");
        // email was sent, or an exception would have been thrown
        message = "Email sent, it should arrive shortly, otherwise check your spam folder";
        messageType = JOptionPane.INFORMATION_MESSAGE;
      } catch (final IOException ioe) {
        message = "Unable to send email: " + ioe.getMessage();
      } finally {
        // now that we have a result, marshall it back unto the swing thread
        final String finalMessage = message;
        final int finalMessageType = messageType;
        SwingUtilities.invokeLater(() -> {
          try {
            GameRunner.showMessageDialog(
                finalMessage,
                GameRunner.Title.of("Email Test"),
                finalMessageType);
          } catch (final HeadlessException e) {
            // should never happen in a GUI app
          }
        });
        progressWindow.setVisible(false);
      }
    };
    // start a background thread
    final Thread t = new Thread(runnable);
    t.start();
  }

public static JsonNode loadNode(final String resourcePath) {
        try {
            final InputStream resourceStream = ConfigLoader.class.getResourceAsStream(resourcePath);
            final JsonNode node = OBJECT_MAPPER.readTree(resourceStream);
            // Ensure the resource stream is not null before closing it
            if (resourceStream == null) {
                throw new ConfigLoaderLoadingException("Resource not found: " + resourcePath);
            }
            resourceStream.close();
            return node;
        } catch (final IOException e) {
            throw new ConfigLoaderLoadingException("An error has occurred while reading or parsing the resource", e);
        }
    }

private void saveToFile(ResContainer rc, File outFile) {
		CodeWriter cw = rc.getContent();
		if (cw != null) {
			cw.save(outFile);
			return;
		}
		InputStream binary = rc.getBinary();
		if(binary != null) {
			try {
				outFile.getParentFile().mkdirs();
				FileOutputStream binaryFileStream = new FileOutputStream(outFile);
				IOUtils.copy(binary, binaryFileStream);
				binaryFileStream.close();
				binary.close();
			}
			catch(IOException e) {
				LOG.warn("Resource '{}' not saved, got exception {}", rc.getName(), e);
			}
			return;
		}
		LOG.warn("Resource '{}' not saved, unknown type", rc.getName());
	}
